import React, { useState } from "react";
import { Link } from "react-router-dom";
import api from "../services/api";

const RegisterPage = () => {
  const [formData, setFormData] = useState({
    username: "",
    email: "",
    password: "",
  });

  const [message, setMessage] = useState("");

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const response = await api.post("/auth/register", formData);
      const data = response.data;
      setMessage(`¡Usuario ${data.username || formData.username} registrado con éxito! Ya puedes iniciar sesión.`);
    } catch (error) {
      if (error.response) {
        setMessage("Error en el registro. Revisa los datos.");
      } else {
        setMessage("No se pudo conectar con el servidor.");
      }
    }
  };

  return (
    <div style={{ textAlign: "center", marginTop: "50px" }}>
      <h1>Bienvenido a To-Do List</h1>
      <div style={{ padding: "20px", display: "inline-block", textAlign: "left", maxWidth: "400px" }}>
        <h2>Crear Cuenta</h2>
        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: "10px" }}>
            <label style={{ display: "block" }}>Usuario:</label>
            <input
              type="text"
              name="username"
              value={formData.username}
              onChange={handleChange}
              required
              style={{ width: "100%" }}
            />
          </div>
          <div style={{ marginBottom: "10px" }}>
            <label style={{ display: "block" }}>Email:</label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              required
              style={{ width: "100%" }}
            />
          </div>
          <div style={{ marginBottom: "10px" }}>
            <label style={{ display: "block" }}>Contraseña:</label>
            <input
              type="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              required
              style={{ width: "100%" }}
            />
          </div>
          <button type="submit" style={{ marginTop: "10px", width: "100%" }}>
            Registrarse
          </button>
        </form>
        {message && <p>{message}</p>}
      </div>
      <div style={{ marginTop: "20px" }}>
        <Link to="/login">¿Ya tienes cuenta? Inicia sesión</Link>
      </div>
    </div>
  );
};

export default RegisterPage;
